import { uuidv7 } from '@motivation/shared';
import type { ImageScope } from '../files.service.js';

/**
 * IndexedDB queue for image uploads pending upload to the server. Story 124.
 *
 * Lives in its own database (mirroring DLR #96 / story 090's client-log queue)
 * because:
 *   - The OPFS SQLite replica is wiped on every snapshot import; queued blobs
 *     would be lost.
 *   - The SW needs access to the queue from the `sync` event handler, where
 *     the OPFS-backed Worker DB is not reachable.
 *   - Bytes don't belong in the `_pending_changes` sync stream — DLR #129.
 *
 * Each entry stores the original Blob, the target scope, and an optional
 * client-side correlation id (`local_ref`) so the screen that enqueued the
 * upload can match the server's returned image_path back to its local row.
 */

const DB_NAME = 'motivation-image-uploads';
const DB_VERSION = 1;
const STORE = 'entries';
const INDEX_UPLOADED = 'uploaded_at';

/**
 * Stored shape — bytes live as an ArrayBuffer with the MIME type beside them
 * so retrieval reconstructs a real Blob. fake-indexeddb does not preserve
 * Blob instances across put/get, and reconstruction is cheap.
 */
export interface StoredImageUploadEntry {
    id: string;
    scope: ImageScope;
    bytes: ArrayBuffer;
    mime_type: string;
    filename: string;
    enqueued_at: string;
    local_ref?: string;
    uploaded_at: string;
    image_path: string;
}

export interface ImageUploadQueueEntry {
    id: string;
    scope: ImageScope;
    blob: Blob;
    filename: string;
    enqueued_at: string;
    /** Optional correlation id provided by the enqueuer (e.g. food_item id). */
    local_ref?: string;
    /** Empty string while pending — populated when the SW drains successfully. */
    uploaded_at: string;
    /** Server-assigned image_path once uploaded. Empty while pending. */
    image_path: string;
}

function toQueueEntry(stored: StoredImageUploadEntry): ImageUploadQueueEntry {
    return {
        id: stored.id,
        scope: stored.scope,
        blob: new Blob([stored.bytes], { type: stored.mime_type }),
        filename: stored.filename,
        enqueued_at: stored.enqueued_at,
        local_ref: stored.local_ref,
        uploaded_at: stored.uploaded_at,
        image_path: stored.image_path,
    };
}

let dbPromise: Promise<IDBDatabase> | null = null;

function getDb(): Promise<IDBDatabase> {
    if (!dbPromise) dbPromise = open();
    return dbPromise;
}

function open(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
        const req = indexedDB.open(DB_NAME, DB_VERSION);
        req.onupgradeneeded = () => {
            const db = req.result;
            if (!db.objectStoreNames.contains(STORE)) {
                const store = db.createObjectStore(STORE, { keyPath: 'id' });
                store.createIndex(INDEX_UPLOADED, 'uploaded_at', { unique: false });
            }
        };
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error ?? new Error('Failed to open image-upload IndexedDB'));
    });
}

function awaitTx(tx: IDBTransaction): Promise<void> {
    return new Promise((resolve, reject) => {
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error ?? new Error('IndexedDB transaction failed'));
        tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
    });
}

export interface EnqueueOptions {
    /** Optional correlation id (e.g. local food_item id) returned with the upload result. */
    local_ref?: string;
}

/**
 * Enqueue an image for later upload. Returns the queue id; the placeholder
 * stored on the originating row should be `pending:<queue id>` so the screen
 * can render a loading state until the SW drains the queue.
 */
async function blobToArrayBuffer(blob: Blob): Promise<ArrayBuffer> {
    // Real browsers support Blob.arrayBuffer; jsdom older versions don't.
    if (typeof (blob as Blob & { arrayBuffer?: unknown }).arrayBuffer === 'function') {
        return blob.arrayBuffer();
    }
    return new Promise<ArrayBuffer>((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
            if (reader.result instanceof ArrayBuffer) resolve(reader.result);
            else reject(new Error('FileReader did not return ArrayBuffer'));
        };
        reader.onerror = () => reject(reader.error ?? new Error('Failed to read blob'));
        reader.readAsArrayBuffer(blob);
    });
}

export async function enqueueImageUpload(
    scope: ImageScope,
    blob: Blob,
    filename = 'image',
    options: EnqueueOptions = {},
): Promise<string> {
    const id = uuidv7();
    const bytes = await blobToArrayBuffer(blob);
    const stored: StoredImageUploadEntry = {
        id,
        scope,
        bytes,
        mime_type: blob.type || 'application/octet-stream',
        filename,
        enqueued_at: Temporal.Now.instant().toString(),
        local_ref: options.local_ref,
        uploaded_at: '',
        image_path: '',
    };
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    tx.objectStore(STORE).put(stored);
    await awaitTx(tx);
    return id;
}

export async function getPendingUploads(limit = 25): Promise<ImageUploadQueueEntry[]> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readonly');
    const index = tx.objectStore(STORE).index(INDEX_UPLOADED);
    const range = IDBKeyRange.only('');
    const out: ImageUploadQueueEntry[] = [];
    return new Promise((resolve, reject) => {
        const req = index.openCursor(range);
        req.onsuccess = () => {
            const cursor = req.result;
            if (!cursor || out.length >= limit) {
                resolve(out);
                return;
            }
            out.push(toQueueEntry(cursor.value as StoredImageUploadEntry));
            cursor.continue();
        };
        req.onerror = () => reject(req.error ?? new Error('Failed to read image upload queue'));
    });
}

export async function markUploaded(id: string, imagePath: string, when: string = Temporal.Now.instant().toString()): Promise<void> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    const store = tx.objectStore(STORE);
    const getReq = store.get(id);
    await new Promise<void>((resolve, reject) => {
        getReq.onsuccess = () => {
            const row = getReq.result as StoredImageUploadEntry | undefined;
            if (!row) {
                resolve();
                return;
            }
            row.uploaded_at = when;
            row.image_path = imagePath;
            const putReq = store.put(row);
            putReq.onsuccess = () => resolve();
            putReq.onerror = () => reject(putReq.error ?? new Error('Failed to update upload row'));
        };
        getReq.onerror = () => reject(getReq.error ?? new Error('Failed to read upload row'));
    });
    await awaitTx(tx);
}

export async function deleteUpload(id: string): Promise<void> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    tx.objectStore(STORE).delete(id);
    await awaitTx(tx);
}

export async function getUploadedRecords(): Promise<ImageUploadQueueEntry[]> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readonly');
    const out: ImageUploadQueueEntry[] = [];
    return new Promise((resolve, reject) => {
        const req = tx.objectStore(STORE).openCursor();
        req.onsuccess = () => {
            const cursor = req.result;
            if (!cursor) {
                resolve(out.filter((e) => e.uploaded_at !== ''));
                return;
            }
            out.push(toQueueEntry(cursor.value as StoredImageUploadEntry));
            cursor.continue();
        };
        req.onerror = () => reject(req.error ?? new Error('Failed to read image upload queue'));
    });
}

/** Test-only: close cached DB so a fresh `indexedDB` global can be substituted between tests. */
export function resetImageUploadStoreForTests(): void {
    if (dbPromise) {
        void dbPromise.then((db) => db.close()).catch(() => undefined);
    }
    dbPromise = null;
}

export const IMAGE_UPLOAD_SYNC_TAG = 'push-image-uploads';
