import { API_URL } from '../../config.js';
import {
    IMAGE_UPLOAD_SYNC_TAG,
    deleteUpload,
    getPendingUploads,
    markUploaded,
    type ImageUploadQueueEntry,
} from './image-upload-store.js';

/**
 * Drains the image upload queue. Each pending entry is POSTed to
 * /api/files/images (multipart) and, on success, marked uploaded with the
 * server-assigned image_path. Story 124.
 *
 * On error the entry is left in place — the next Background Sync fire (or
 * a manual retry) tries again. Throws so the SW's `event.waitUntil` reports
 * the failure to the browser, which will re-fire `sync` once connectivity
 * returns.
 */

export const IMAGE_UPLOAD_SUCCESS_CHANNEL = 'motivation-image-uploads';

export interface ImageUploadSuccessMessage {
    type: 'image-upload-success';
    queue_id: string;
    image_path: string;
    local_ref?: string;
}

export interface ShippingDeps {
    fetch?: typeof fetch;
    apiUrl?: string;
    now?: () => string;
    /** Override the broadcast channel for tests; default opens IMAGE_UPLOAD_SUCCESS_CHANNEL. */
    broadcast?: (message: ImageUploadSuccessMessage) => void;
}

export interface ShippingResult {
    uploaded: number;
    failed: number;
}

export async function shipPendingImageUploads(deps: ShippingDeps = {}): Promise<ShippingResult> {
    const fetchImpl = deps.fetch ?? fetch.bind(globalThis);
    const apiBase = deps.apiUrl ?? API_URL;
    const now = deps.now ?? (() => Temporal.Now.instant().toString());
    const broadcast = deps.broadcast ?? defaultBroadcast;

    let uploaded = 0;
    let failed = 0;
    const errors: Error[] = [];

    while (true) {
        const batch = await getPendingUploads(25);
        if (batch.length === 0) break;

        for (const entry of batch) {
            try {
                const imagePath = await uploadOne(entry, fetchImpl, apiBase);
                await markUploaded(entry.id, imagePath, now());
                broadcast({
                    type: 'image-upload-success',
                    queue_id: entry.id,
                    image_path: imagePath,
                    local_ref: entry.local_ref,
                });
                uploaded += 1;
                // Drop the entry once consumers have been notified; the
                // success event carries everything they need.
                await deleteUpload(entry.id);
            } catch (err) {
                failed += 1;
                errors.push(err instanceof Error ? err : new Error(String(err)));
                // Leave the entry in place for the next retry; don't try the
                // rest of the batch in this fire — they'll re-surface on the
                // next sync wake-up.
                break;
            }
        }

        if (failed > 0) break;
    }

    if (errors.length > 0) {
        // Throw the first error so the SW's `event.waitUntil` surfaces it and
        // the browser retries `sync` on the next connectivity change.
        throw errors[0];
    }

    return { uploaded, failed };
}

async function uploadOne(entry: ImageUploadQueueEntry, fetchImpl: typeof fetch, apiBase: string): Promise<string> {
    const form = new FormData();
    form.set('image', entry.blob, entry.filename || 'image');
    const response = await fetchImpl(`${apiBase}/api/files/images?scope=${encodeURIComponent(entry.scope)}`, {
        method: 'POST',
        body: form,
    });
    if (!response.ok) {
        const text = await response.text().catch(() => '');
        throw new Error(`Image upload failed (${response.status}): ${text || response.statusText}`);
    }
    const body = await response.json() as { image_path?: string };
    if (!body.image_path) throw new Error('Server response did not include image_path');
    return body.image_path;
}

function defaultBroadcast(message: ImageUploadSuccessMessage): void {
    if (typeof BroadcastChannel === 'undefined') return;
    const ch = new BroadcastChannel(IMAGE_UPLOAD_SUCCESS_CHANNEL);
    try {
        ch.postMessage(message);
    } finally {
        ch.close();
    }
}

/**
 * Registers the Background Sync tag. Called by the main thread after
 * enqueuing an upload offline (or after a flaky online upload failed). Throws
 * if Background Sync is unavailable — the app is Chrome-only with secure-
 * origin flags, so we Fail Loud per development_principles.md.
 */
export async function requestImageUploadSync(): Promise<void> {
    if (typeof navigator === 'undefined' || !navigator.serviceWorker) {
        throw new Error('Service Worker is not available — image uploads cannot ship');
    }
    const registration = await navigator.serviceWorker.ready;
    if (!registration.sync) {
        throw new Error('Background Sync API is not available — image uploads cannot ship');
    }
    await registration.sync.register(IMAGE_UPLOAD_SYNC_TAG);
}
