/**
 * Cache-first strategy for image GETs served by /api/files/images/*.
 *
 * Hash-keyed paths (images/<scope>/<uuidv7>/...) make every URL content-stable,
 * so cached responses never need revalidation. The server also sends
 * `Cache-Control: public, max-age=31536000, immutable`. We use a dedicated
 * cache so a future eviction policy (or version bump) doesn't drag along the
 * app shell or vice versa.
 *
 * Story 124. Errors from the fetch propagate untouched — the cache miss path
 * is identical to a normal `<img>` load failure, which is what we want.
 */

export const IMAGE_CACHE_NAME = 'motivation-images-v1';

const IMAGE_PATH_RE = /\/api\/files\/images\/(food|meal|ai)\/[0-9a-f]{8}-[0-9a-f]{4}-7[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}\/(display\.jpg|original\.(jpg|jpeg|png|webp))$/;

/**
 * Returns true when `url` (a pathname or full URL) is one of the image-serve
 * GETs we want to cache. False for the upload endpoint and for unrelated paths.
 */
export function isImageServeUrl(url: string): boolean {
    let pathname: string;
    try {
        pathname = new URL(url, 'http://example.invalid').pathname;
    } catch {
        return false;
    }
    return IMAGE_PATH_RE.test(pathname);
}

/**
 * Cache-first fetch for a stable image URL. Populates the dedicated image
 * cache on the first successful hit; subsequent hits skip the network.
 */
export async function cacheFirstImage(
    request: Request,
    fetchImpl: typeof fetch = fetch,
    cachesLike: CacheStorage = caches,
    cacheName: string = IMAGE_CACHE_NAME,
): Promise<Response> {
    const cache = await cachesLike.open(cacheName);
    const cached = await cache.match(request);
    if (cached) return cached;

    const response = await fetchImpl(request);
    if (response.ok) {
        await cache.put(request, response.clone());
    }
    return response;
}
